### Programmatic deployment using @vercel/client (Node.js)

Source: https://context7.com/vercel/vercel/llms.txt

Node.js example showing how to create deployments programmatically with @vercel/client using an async iterator to receive event-driven progress updates. Dependencies: @vercel/client package, Node.js, and VERCEL_TOKEN (and optional VERCEL_TEAM_ID). Inputs: local project path, metadata, and options; output: deployment URL or thrown error on failure. Limitations: long-running network operations and credentials must be available in the environment.

```javascript
const { createDeployment } = require('@vercel/client');
const path = require('path');

async function deployToVercel() {
  const projectPath = path.join(__dirname, 'my-app');
  let deploymentUrl = null;

  try {
    for await (const event of createDeployment({
      token: process.env.VERCEL_TOKEN,
      teamId: process.env.VERCEL_TEAM_ID,
      path: projectPath,
      project: 'my-application',
      target: 'production',
      forceNew: false,
      withCache: true,
      meta: {
        githubCommitSha: process.env.GITHUB_SHA,
        githubCommitRef: process.env.GITHUB_REF,
        githubCommitMessage: 'Deploy from CI',
        githubCommitAuthorName: 'GitHub Actions',
      },
    })) {
      switch (event.type) {
        case 'hashes-calculated':
          console.log(`Calculated hashes for ${Object.keys(event.payload).length} files`);
          break;

        case 'file-count':
          console.log(`Uploading ${event.payload.total} files (${event.payload.missing} new)`);
          break;

        case 'file-uploaded':
          console.log(`Uploaded: ${event.payload.name} (${event.payload.size} bytes)`);
          break;

        case 'all-files-uploaded':
          console.log('All files uploaded successfully');
          break;

        case 'created':
          console.log(`Deployment created: ${event.payload.id}`);
          console.log(`Building at: https://${event.payload.url}`);
          break;

        case 'building':
          console.log('Build in progress...');
          break;

        case 'ready':
          deploymentUrl = event.payload.url;
          console.log(`Deployment ready: https://${deploymentUrl}`);
          console.log(`Inspect URL: ${event.payload.inspectorUrl}`);
          break;

        case 'alias-assigned':
          console.log(`Alias assigned: https://${event.payload.alias}`);
          break;

        case 'warning':
          console.warn(`Warning: ${event.payload.message}`);
          break;

        case 'error':
          console.error(`Error: ${event.payload.message}`);
          throw new Error(event.payload.message);
      }
    }

    return deploymentUrl;
  } catch (error) {
    console.error('Deployment failed:', error.message);
    throw error;
  }
}

deployToVercel().then(url => {
  console.log(`Successfully deployed to: https://${url}`);
  process.exit(0);
}).catch(error => {
  console.error('Failed to deploy:', error);
  process.exit(1);
});
```

